fn solve(mut nums: Vec<i64>, k: i64) -> i64 {
    nums.sort();
    let n = nums.len();
    let mut i = 0;
    let mut max_len = 0;
    for j in 0..n {
        while i <= j && nums[i] * k < nums[j] {
            i += 1;
        }
        let len = j - i + 1;
        if len > max_len {
            max_len = len;
        }
    }
    n as i64 - max_len as i64
}
```

